import{tasksCheckbox}from"./tasksCheckbox";import{editDeleteTasks}from"@js/editDeleteTasks.js";export function AddList(){document.querySelector(".table__tasks_add").addEventListener("click",()=>{document.querySelector(".task-form-overlay").style.display="flex",document.querySelector(".task-form__close").addEventListener("click",()=>{document.querySelector(".task-form-overlay").style.display="none",document.querySelector(".task-form__input").value="",document.querySelector(".task-form__textarea").value=""}),document.querySelector(".task-form__btn--submit").addEventListener("click",()=>{const e=document.querySelector(".task-form__input").value,t=document.querySelector(".task-form__textarea").value;document.querySelector(".task-form__input").value="",document.querySelector(".task-form__textarea").value="",document.querySelector(".task-form-overlay").style.display="none",saveTasks(e,t),loadTasks()})})}function saveTasks(e,t){let s=JSON.parse(localStorage.getItem("tasks"))||[];s.push({id:s.length>0?s[s.length-1].id+1:0,title:e,text:t,completed:!1}),localStorage.setItem("tasks",JSON.stringify(s))}export function loadTasks(e,t){document.querySelector(".table__tasks").innerHTML="";let s=JSON.parse(localStorage.getItem("tasks"))||[];if(e&&(s=s.filter(s=>s[e]===t)),s.forEach(e=>{const t=document.createElement("div");t.className="table__tasks-item",t.setAttribute("data-id",e.id),t.innerHTML=`\n            <h3 class="table__tasks-item_name">${e.title}</h3>\n            <p class="table__tasks-item_text">${e.text}</p>\n            <input type="checkbox" class="table__tasks-item_done">\n            <button class="table__tasks-item_edit edit">🖊️</button>\n            <button class="table__tasks-item_edit delete">🛒</button>\n        `,document.querySelector(".table__tasks").appendChild(t),t.querySelector(".table__tasks-item_done").checked=e.completed||!1,t.querySelector(".table__tasks-item_done").addEventListener("change",tasksCheckbox)}),!0===t){document.querySelector(".completed").checked=!0,document.querySelector(".active").checked=!1;const e=new URL(window.location.href);e.searchParams.set("filter","completed"),window.history.pushState({},"",e)}else if(!1===t){document.querySelector(".active").checked=!0,document.querySelector(".completed").checked=!1;const e=new URL(window.location.href);e.searchParams.set("filter","active"),window.history.pushState({},"",e)}else document.querySelector(".active").checked=!1,document.querySelector(".completed").checked=!1;editDeleteTasks()}